css:
body {
  background-color: #0B1610 !important;
}
.header {
  background: linear-gradient(
    180deg,
    color-mix(in srgb, #1E3420 var(--ts-opacity-header), transparent) 0%,
    color-mix(in srgb, #162618 var(--ts-opacity-header), transparent) 100%
  ) !important;
  border-bottom: 2px solid color-mix(in srgb, #8B1A1A var(--ts-opacity-header), transparent) !important;
}
.sidebar {
  background: linear-gradient(180deg, #162618 0%, #1A2E1C 50%, #0F1E14 100%) !important;
  border-right: 2px solid #2E5030 !important;
}
.album-row {
  background: color-mix(in srgb, #1A2E1C var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
  border: 1.5px solid color-mix(in srgb, #2E5030 var(--ts-row-surface-opacity, var(--ts-opacity-row)), transparent) !important;
}
.album-row:hover {
  background: color-mix(in srgb, #28422A var(--ts-opacity-row), transparent) !important;
  border-color: color-mix(in srgb, #8B1A1A var(--ts-opacity-row), transparent) !important;
}
.album-row.album-row-header, .album-row.album-row-header:hover {
  background: color-mix(in srgb, #8B1A1A var(--ts-row-surface-opacity, var(--ts-opacity-row-header-background)), transparent) !important;
  border: 1.5px solid color-mix(in srgb, #6B1414 var(--ts-row-surface-opacity, var(--ts-opacity-row-header-background)), transparent) !important;
  color: #EAF0E8 !important;
}
.album-row.album-row-header .sort-indicator { color: #9A8450 !important; }
.album-row.album-row-header .album-row-header-separator { color: #9A8450 !important; }
.row-rating { font-weight: 700 !important; color: #A62121 !important; }
.row-album a { font-weight: 600 !important; color: #A62121 !important; }
.card-title, .card-title a { color: #A62121 !important; }
.card-rating:not(.unrated) { color: #A62121 !important; }
.album-card {
  background: color-mix(in srgb, #1A2E1C var(--ts-opacity-card), transparent) !important;
  border: 1.5px solid color-mix(in srgb, #2E5030 var(--ts-opacity-card), transparent) !important;
  border-radius: 12px !important;
}
.album-card:hover {
  border-color: color-mix(in srgb, #8B1A1A var(--ts-opacity-card), transparent) !important;
}
.card-info {
  background: color-mix(in srgb, #162618 var(--ts-opacity-card), transparent) !important;
}
.modal {
  background: linear-gradient(180deg, #1A2E1C 0%, #162618 100%) !important;
  border: 2px solid #8B1A1A !important;
  border-radius: 14px !important;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
}
button {
  background: linear-gradient(180deg, #2E5030 0%, #1E3420 100%) !important;
  border: 1.5px solid #3D6040 !important;
  color: #EAF0E8 !important;
}
button:hover {
  background: linear-gradient(180deg, #3D6040 0%, #2E5030 100%) !important;
  border-color: #8B1A1A !important;
}
a, .artist-link { color: #8B1A1A !important; }
a:hover, .artist-link:hover { color: #A82020 !important; }
.row-notes .notes-link,
.wrapped .w-notable-quote .notes-link,
.wrapped .w-ticker-chip-text .notes-link,
.wrapped .w-notes-list-text .notes-link,
.row-notes .notes-link:hover,
.wrapped .w-notable-quote .notes-link:hover,
.wrapped .w-ticker-chip-text .notes-link:hover,
.wrapped .w-notes-list-text .notes-link:hover,
.row-notes .notes-link:focus-visible,
.wrapped .w-notable-quote .notes-link:focus-visible,
.wrapped .w-ticker-chip-text .notes-link:focus-visible,
.wrapped .w-notes-list-text .notes-link:focus-visible {
  color: inherit !important;
}
input, select, textarea {
  background: #0F1E14 !important;
  border: 1.5px solid #2E5030 !important;
  color: #EAF0E8 !important;
}
input:focus, select:focus, textarea:focus {
  border-color: #8B1A1A !important;
  box-shadow: 0 0 0 3px rgba(139, 26, 26, 0.15);
}
::selection { background: #8B1A1A; color: #EAF0E8; }
